import React from "react";
import { Link, useLocation } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";

export default function Navbar({ user }) {
  const { logout } = useAuth();
  const location = useLocation();

  const navItems = [
    { path: "/", label: "Home", icon: "🏠" },
    { path: "/academic", label: "Academic", icon: "📚" },
    { path: "/food", label: "Food", icon: "🍽️" },
    { path: "/laundry", label: "Laundry", icon: "🧺" },
    { path: "/complaint", label: "Complaint", icon: "📋" },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="sticky top-0 z-40 navbar">
      <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
        <div className="flex items-center gap-8">
          <Link to="/" className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-blue-500 bg-clip-text text-transparent hover:opacity-80 transition">
            UniEase
          </Link>

          <div className="hidden md:flex gap-2">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all duration-300 ${
                  isActive(item.path)
                    ? "tab-active bg-blue-100 text-blue-700 font-semibold"
                    : "tab-inactive text-slate-600 hover:bg-slate-100"
                }`}
              >
                <span className="text-lg">{item.icon}</span>
                <span className="text-sm font-medium">{item.label}</span>
              </Link>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center text-white font-bold shadow-md">
              {user?.name?.[0] || "S"}
            </div>
            <div className="hidden sm:block">
              <p className="text-sm font-semibold text-slate-900">{user?.name}</p>
              <p className="text-xs text-slate-600">Student</p>
            </div>
          </div>

          <button
            onClick={logout}
            className="px-4 py-2 bg-gradient-to-r from-red-500 to-red-600 hover:shadow-lg hover:scale-105 text-white rounded-lg font-semibold transition-all duration-300 text-sm"
          >
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
}
